#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <math.h>
#include <time.h>
#include <stdint.h>

#define MAX_ORDERS 200

// Structure to represent an order
typedef struct {
    int start_time;
    int num_items;
    int deadline;
    int penalty;
} Order;

// Comparison function for sorting orders
int compare_orders(const void *a, const void *b) {
    Order *order1 = (Order *)a;
    Order *order2 = (Order *)b;
    if (order1->deadline < order2->deadline) return -1;
    if (order1->deadline > order2->deadline) return 1;
    if (order1->penalty < order2->penalty) return -1;
    if (order1->penalty > order2->penalty) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Order orders[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d %d %d", &orders[i].start_time, &orders[i].num_items, &orders[i].deadline, &orders[i].penalty);
        }
        qsort(orders, N, sizeof(Order), compare_orders);
        int current_time = 0;
        int total_penalty = 0;
        for (int i = 0; i < N; i++) {
            int items_cooked = 0;
            while (current_time < orders[i].deadline && items_cooked < orders[i].num_items) {
                current_time++;
                items_cooked++;
            }
            if (items_cooked < orders[i].num_items) {
                total_penalty += (orders[i].num_items - items_cooked) * orders[i].penalty;
            }
        }
        printf("%d\n", total_penalty);
    }
    return 0;
}

