import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Order implements Comparable<Order> {
        int start_time;
        int num_items;
        int deadline;
        int penalty;

        public Order(int start_time, int num_items, int deadline, int penalty) {
            this.start_time = start_time;
            this.num_items = num_items;
            this.deadline = deadline;
            this.penalty = penalty;
        }

        @Override
        public int compareTo(Order o) {
            if (this.deadline < o.deadline) return -1;
            if (this.deadline > o.deadline) return 1;
            if (this.penalty < o.penalty) return -1;
            if (this.penalty > o.penalty) return 1;
            return 0;
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        while (T-- > 0) {
            int N = scanner.nextInt();
            Order[] orders = new Order[N];
            for (int i = 0; i < N; i++) {
                orders[i] = new Order(scanner.nextInt(), scanner.nextInt(), scanner.nextInt(), scanner.nextInt());
            }
            Arrays.sort(orders);
            int current_time = 0;
            int total_penalty = 0;
            for (int i = 0; i < N; i++) {
                int items_cooked = 0;
                while (current_time < orders[i].deadline && items_cooked < orders[i].num_items) {
                    current_time++;
                    items_cooked++;
                }
                if (items_cooked < orders[i].num_items) {
                    total_penalty += (orders[i].num_items - items_cooked) * orders[i].penalty;
                }
            }
            System.out.println(total_penalty);
        }
    }
}

